from jsonpath_ng import parse


def parse_using_jsonpath(record, jsonpath_expr, column_headers=[], **kwargs):
    '''
    Method to parse data using json_path ["employees":[{"id":1},{"id":2}]] -> {"id":1},{"id":2}
    :param record: json record
    :param jsonpath_expr: jsonpath_expr
    :param kwargs: to handle generic named parameters
    :return: parsed_data
    '''
    print('Parsing json output using jsonpath expressions')
    parsed_data = []
    parsed_data += [match.value for match in jsonpath_expr.find(record) if match.value != []]
    return parsed_data


def parse_individual_fields_using_jsonpath(record, jsonpath_expr, column_headers=[], **kwargs):
    '''
    Method to parse data using json_path {"employees": [{"id": 1,"name": "Pankaj"},{"name": "David","salary": "5000","id": 2}]} -> [{"id": 1,"name": "Pankaj"},{"name": "David","salary": "5000","id": 2}]
    :param record: json record
    :param jsonpath_expr: jsonpath_expr
    :param kwargs: to handle generic named parameters
    :return: parsed_data
    '''
    print('Parsing json output using jsonpath expressions')
    print(record)
    # input: {"employees": [{"id": 1,"name": "Pankaj"},{"name": "David","salary": "5000","id": 2}]}
    # dict = {"index1":[{"id": 1},{"name": "Pankaj"}],"index2":[{"id": 2},{"name": "David"}]}
    parsed_data = []
    data = {}
    #
    for match in jsonpath_expr.find(record):
        if match.value:
            if match.context.path not in data:
                data[match.context.path] = []
            data[match.context.path].append({str(match.path): match.value})
    # input: {"index1":[{"id": 1},{"name": "Pankaj"}],"index2":[{"id": 2},{"name": "David"}]}
    # Array = [[{"id": 1},{"name": "Pankaj"}],[{"id": 2},{"name": "David"}]]
    for d in data.values():
        parsed_data.append(d)

    combined_dict = {}
    final_dict = []
    # input = [[{"id": 1},{"name": "Pankaj"}],[{"id": 2},{"name": "David"}]]
    # output = [{"id": 1,"name": "Pankaj"},{"id": 2,"name": "David"}]
    for i in parsed_data:
        for j in i:
            combined_dict.update(j)
        final_dict.append(combined_dict)
        combined_dict = {}

    print("final_dict")
    print(final_dict)
    return final_dict


